#include <iostream>
#include <vector>
#include <memory>
#include <cmath>
#include <iomanip>
#include <sstream>

// Base class
class Shape {
public:
    virtual double calculateArea() const = 0;
    virtual ~Shape() = default;
};

// Derived class: Circle
class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r) : radius(r) {}
    double calculateArea() const override {
        return M_PI * radius * radius;
    }
};

// Derived class: Rectangle
class Rectangle : public Shape {
private:
    double width;
    double height;
public:
    Rectangle(double w, double h) : width(w), height(h) {}
    double calculateArea() const override {
        return width * height;
    }
};

int main() {
    std::stringstream ss;
    ss << "Calculating areas:" << std::endl;

    // Using smart pointers for correct memory management in the driver
    std::vector<std::unique_ptr<Shape>> shapes_driver;
    shapes_driver.push_back(std::make_unique<Circle>(5.0));
    shapes_driver.push_back(std::make_unique<Rectangle>(4.0, 6.0));
    shapes_driver.push_back(std::make_unique<Circle>(3.0));
    shapes_driver.push_back(std::make_unique<Rectangle>(2.5, 7.0));

    for (size_t i = 0; i < shapes_driver.size(); ++i) {
        ss << "Shape " << i + 1 << " Area: " << std::fixed << std::setprecision(4) << shapes_driver[i]->calculateArea() << std::endl;
    }

    std::cout << ss.str();
    return 0;
}
